import Long from "long";
async function importContacts(client, contacts) {
  let seq = Long.ZERO;
  const contactsNorm = contacts.map((input) => ({
    _: "inputPhoneContact",
    clientId: seq = seq.add(1),
    ...input
  }));
  return client.call({
    _: "contacts.importContacts",
    contacts: contactsNorm
  });
}
